import { create } from 'zustand';
import { patientApi } from '@/services/api';
import type { Patient, PaginatedResponse } from '@pacsviewer/shared/types';

interface PatientFilters {
  gender?: 'male' | 'female' | 'other';
  tags?: string[];
  minAge?: number;
  maxAge?: number;
}

interface PatientState {
  // List state
  patients: Patient[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
  loading: boolean;
  error: string | null;

  // Selected patient
  selectedPatient: Patient | null;
  selectedPatientLoading: boolean;

  // Search
  searchQuery: string;
  searchResults: Patient[];
  searchLoading: boolean;

  // Filters
  filters: PatientFilters;

  // Actions
  fetchPatients: (page?: number) => Promise<void>;
  fetchPatientById: (id: string) => Promise<void>;
  createPatient: (data: Partial<Patient>) => Promise<Patient | null>;
  updatePatient: (id: string, data: Partial<Patient>) => Promise<Patient | null>;
  deletePatient: (id: string) => Promise<boolean>;
  searchPatients: (query: string) => Promise<void>;
  setSelectedPatient: (patient: Patient | null) => void;
  setFilters: (filters: Partial<PatientFilters>) => void;
  clearSearch: () => void;
  clearError: () => void;
}

export const usePatientStore = create<PatientState>((set, get) => ({
  // Initial state
  patients: [],
  total: 0,
  page: 1,
  pageSize: 20,
  totalPages: 0,
  loading: false,
  error: null,

  selectedPatient: null,
  selectedPatientLoading: false,

  searchQuery: '',
  searchResults: [],
  searchLoading: false,

  filters: {},

  // Fetch patients list
  fetchPatients: async (page = 1) => {
    set({ loading: true, error: null });
    try {
      const { pageSize, filters } = get();
      const response = await patientApi.getAll({
        page,
        pageSize,
        ...filters,
      });
      const data = response.data as PaginatedResponse<Patient>;
      set({
        patients: data.items,
        total: data.total,
        page: data.page,
        pageSize: data.pageSize,
        totalPages: data.totalPages,
        loading: false,
      });
    } catch (error) {
      set({
        error: error instanceof Error ? error.message : '获取患者列表失败',
        loading: false,
      });
    }
  },

  // Fetch single patient by ID
  fetchPatientById: async (id: string) => {
    set({ selectedPatientLoading: true, error: null });
    try {
      const response = await patientApi.getById(id);
      set({
        selectedPatient: response.data as Patient,
        selectedPatientLoading: false,
      });
    } catch (error) {
      set({
        error: error instanceof Error ? error.message : '获取患者信息失败',
        selectedPatientLoading: false,
      });
    }
  },

  // Create patient
  createPatient: async (data: Partial<Patient>) => {
    set({ loading: true, error: null });
    try {
      const response = await patientApi.create(data);
      const newPatient = response.data as Patient;
      set((state) => ({
        patients: [newPatient, ...state.patients],
        total: state.total + 1,
        loading: false,
      }));
      return newPatient;
    } catch (error) {
      set({
        error: error instanceof Error ? error.message : '创建患者失败',
        loading: false,
      });
      return null;
    }
  },

  // Update patient
  updatePatient: async (id: string, data: Partial<Patient>) => {
    set({ loading: true, error: null });
    try {
      const response = await patientApi.update(id, data);
      const updatedPatient = response.data as Patient;
      set((state) => ({
        patients: state.patients.map((p) =>
          p.id === id ? updatedPatient : p
        ),
        selectedPatient:
          state.selectedPatient?.id === id
            ? updatedPatient
            : state.selectedPatient,
        loading: false,
      }));
