import { create } from 'zustand';
import type { Image, Annotation, Layer } from '@pacsviewer/shared/types';

// Viewport state for Cornerstone.js
interface ViewportState {
  zoom: number;
  pan: { x: number; y: number };
  rotation: number;
  flipH: boolean;
  flipV: boolean;
  windowWidth: number;
  windowLevel: number;
  invert: boolean;
  colormap: string | null;
  voiLUT: any | null;
}

// Active tool types
type ToolType =
  | 'pan'
  | 'zoom'
  | 'rotate'
  | 'flipH'
  | 'flipV'
  | 'windowLevel'
  | 'length'
  | 'angle'
  | 'rectangleRoi'
  | 'ellipseRoi'
  | 'freehandRoi'
  | 'probe'
  | 'arrow'
  | 'text'
  | 'eraser'
  | 'magnify';

// Comparison mode
type ComparisonMode = 'single' | 'sideBySide' | 'overlay' | 'slider';

interface ComparisonConfig {
  mode: ComparisonMode;
  images: string[]; // image IDs
  sliderPosition: number; // 0-100 for slider mode
  overlayOpacity: number; // 0-1 for overlay mode
  synced: boolean; // sync viewport state across images
}

interface ViewerState {
  // Current image
  currentImage: Image | null;
  currentImageLoading: boolean;
  imageStack: string[]; // list of image IDs for navigation
  currentStackIndex: number;

  // Viewport
  viewport: ViewportState;
  viewportReady: boolean;

  // Tools
  activeTool: ToolType;
  toolOptions: Record<string, any>;

  // Annotations
  annotations: Annotation[];
  annotationsLoading: boolean;
  activeAnnotation: Annotation | null;
  annotationHistory: Annotation[][]; // for undo
  annotationFuture: Annotation[][]; // for redo

  // Layers
  layers: Layer[];
  layersLoading: boolean;
  activeLayer: Layer | null;

  // Comparison
  comparison: ComparisonConfig;

  // UI state
  showToolbar: boolean;
  showInfo: boolean;
  showMinimap: boolean;
  isFullscreen: boolean;

  // Actions - Image
  setCurrentImage: (image: Image | null) => void;
  setImageStack: (images: string[], startIndex?: number) => void;
  navigateStack: (direction: 'next' | 'prev' | 'first' | 'last') => void;
  loadImage: (imageId: string) => Promise<void>;

  // Actions - Viewport
  setViewport: (viewport: Partial<ViewportState>) => void;
  resetViewport: () => void;
  fitToWindow: () => void;
  setZoom: (zoom: number) => void;
  setWindowLevel: (windowWidth: number, windowLevel: number) => void;
  setRotation: (rotation: number) => void;
  setFlip: (horizontal: boolean, vertical: boolean) => void;
  setInvert: (invert: boolean) => void;
  setColormap: (colormap: string | null) => void;

  // Actions - Tools
  setActiveTool: (tool: ToolType) => void;
  setToolOption: (key: string, value: any) => void;

  // Actions - Annotations
  setAnnotations: (annotations: Annotation[]) => void;
  addAnnotation: (annotation: Annotation) => void;
  updateAnnotation: (id: string, updates: Partial<Annotation>) => void;
  removeAnnotation: (id: string) => void;
  setActiveAnnotation: (annotation: Annotation | null) => void;
  undoAnnotation: () => void;
  redoAnnotation: () => void;

  // Actions - Layers
  setLayers: (layers: Layer[]) => void;
  addLayer: (layer: Layer) => void;
  updateLayer: (id: string, updates: Partial<Layer>) => void;
  removeLayer: (id: string) => void;
  setActiveLayer: (layer: Layer | null) => void;
  toggleLayerVisibility: (id: string) => void;
  setLayerOpacity: (id: string, opacity: number) => void;

  // Actions - Comparison
  setComparisonMode: (mode: ComparisonMode) => void;
  setComparisonConfig: (config: Partial<ComparisonConfig>) => void;
  addComparisonImage: (imageId: string) => void;
  removeComparisonImage: (imageId: string) => void;

  // Actions - UI
  toggleToolbar: () => void;
  toggleInfo: () => void;
  toggleMinimap: () => void;
  toggleFullscreen: () => void;
}

const defaultViewport: ViewportState = {
  zoom: 1,
  pan: { x: 0, y: 0 },
  rotation: 0,
  flipH: false,
  flipV: false,
  windowWidth: 400,
  windowLevel: 40,
  invert: false,
  colormap: null,
  voiLUT: null,
};

export const useViewerStore = create<ViewerState>((set, get) => ({
  // Initial state
  currentImage: null,
  currentImageLoading: false,
  imageStack: [],
  currentStackIndex: 0,

  viewport: { ...defaultViewport },
  viewportReady: false,

  activeTool: 'windowLevel',
  toolOptions: {},

  annotations: [],
  annotationsLoading: false,
  activeAnnotation: null,
  annotationHistory: [],
  annotationFuture: [],

  layers: [],
  layersLoading: false,
  activeLayer: null,

  comparison: {
    mode: 'single',
    images: [],
    sliderPosition: 50,
    overlayOpacity: 0.5,
    synced: true,
  },

  showToolbar: true,
  showInfo: true,
  showMinimap: false,
  isFullscreen: false,

  // Image actions
  setCurrentImage: (image) => {
    set({
      currentImage: image,
      currentImageLoading: false,
      viewportReady: false,
    });
    // Reset viewport for new image
    get().resetViewport();
  },

  setImageStack: (images, startIndex = 0) => {
    set({
      imageStack: images,
      currentStackIndex: startIndex,
    });
  },

  navigateStack: (direction) => {
    const { imageStack, currentStackIndex } = get();
    let newIndex = currentStackIndex;

    switch (direction) {
      case 'next':
        newIndex = Math.min(currentStackIndex + 1, imageStack.length - 1);
        break;
      case 'prev':
        newIndex = Math.max(currentStackIndex - 1, 0);
        break;
      case 'first':
        newIndex = 0;
        break;
      case 'last':
        newIndex = imageStack.length - 1;
        break;
    }

    if (newIndex !== currentStackIndex) {
      set({ currentStackIndex: newIndex, currentImageLoading: true });
      // Trigger image load in component
    }
  },

  loadImage: async (imageId) => {
    set({ currentImageLoading: true });
    // Image loading is handled by Cornerstone.js in the component
    // This just sets the loading state
  },

  // Viewport actions
  setViewport: (viewport) => {
    set((state) => ({
      viewport: { ...state.viewport, ...viewport },
      viewportReady: true,
    }));
  },

  resetViewport: () => {
    set({ viewport: { ...defaultViewport } });
  },

  fitToWindow: () => {
    set((state) => ({
      viewport: {
        ...state.viewport,
        zoom: 1,
        pan: { x: 0, y: 0 },
      },
    }));
  },

  setZoom: (zoom) => {
    set((state) => ({
      viewport: { ...state.viewport, zoom },
    }));
  },

  setWindowLevel: (windowWidth, windowLevel) => {
    set((state) => ({
      viewport: { ...state.viewport, windowWidth, windowLevel },
    }));
  },

  setRotation: (rotation) => {
    set((state) => ({
      viewport: { ...state.viewport, rotation },
    }));
  },

  setFlip: (horizontal, vertical) => {
    set((state) => ({
      viewport: {
        ...state.viewport,
        flipH: horizontal,
        flipV: vertical,
      },
    }));
  },

  setInvert: (invert) => {
    set((state) => ({
      viewport: { ...state.viewport, invert },
    }));
  },

  setColormap: (colormap) => {
    set((state) => ({
      viewport: { ...state.viewport, colormap },
    }));
  },

  // Tool actions
  setActiveTool: (tool) => {
    set({ activeTool: tool });
  },

  setToolOption: (key, value) => {
    set((state) => ({
      toolOptions: { ...state.toolOptions, [key]: value },
    }));
  },

  // Annotation actions
  setAnnotations: (annotations) => {
    set({ annotations });
  },

  addAnnotation: (annotation) => {
    set((state) => {
      const newAnnotations = [...state.annotations, annotation];
      return {
        annotations: newAnnotations,
        annotationHistory: [...state.annotationHistory, state.annotations],
        annotationFuture: [],
      };
    });
  },

  updateAnnotation: (id, updates) => {
    set((state) => {
      const newAnnotations = state.annotations.map((a) =>
        a.id === id ? { ...a, ...updates } : a
      );
      return {
        annotations: newAnnotations,
        annotationHistory: [...state.annotationHistory, state.annotations],
        annotationFuture: [],
        activeAnnotation:
          state.activeAnnotation?.id === id
            ? { ...state.activeAnnotation, ...updates }
            : state.activeAnnotation,
      };
    });
  },

  removeAnnotation: (id) => {
    set((state) => {
      const newAnnotations = state.annotations.filter((a) => a.id !== id);
      return {
        annotations: newAnnotations,
        annotationHistory: [...state.annotationHistory, state.annotations],
        annotationFuture: [],
        activeAnnotation:
          state.activeAnnotation?.id === id ? null : state.activeAnnotation,
      };
    });
  },

  setActiveAnnotation: (annotation) => {
    set({ activeAnnotation: annotation });
  },

  undoAnnotation: () => {
    set((state) => {
      if (state.annotationHistory.length === 0) return state;
      const previousAnnotations =
        state.annotationHistory[state.annotationHistory.length - 1];
      return {
        annotations: previousAnnotations,
        annotationHistory: state.annotationHistory.slice(0, -1),
        annotationFuture: [state.annotations, ...state.annotationFuture],
      };
    });
  },

  redoAnnotation: () => {
    set((state) => {
      if (state.annotationFuture.length === 0) return state;
      const nextAnnotations = state.annotationFuture[0];
      return {
        annotations: nextAnnotations,
        annotationHistory: [...state.annotationHistory, state.annotations],
        annotationFuture: state.annotationFuture.slice(1),
      };
    });
  },

  // Layer actions
  setLayers: (layers) => {
    set({ layers });
  },

  addLayer: (layer) => {
    set((state) => ({
      layers: [...state.layers, layer],
    }));
  },

  updateLayer: (id, updates) => {
    set((state) => ({
      layers: state.layers.map((l) =>
        l.id === id ? { ...l, ...updates } : l
      ),
      activeLayer:
        state.activeLayer?.id === id
          ? { ...state.activeLayer, ...updates }
          : state.activeLayer,
    }));
  },

  removeLayer: (id) => {
    set((state) => ({
      layers: state.layers.filter((l) => l.id !== id),
      activeLayer: state.activeLayer?.id === id ? null : state.activeLayer,
    }));
  },

  setActiveLayer: (layer) => {
    set({ activeLayer: layer });
  },

  toggleLayerVisibility: (id) => {
    set((state) => ({
      layers: state.layers.map((l) =>
        l.id === id ? { ...l, visible: !l.visible } : l
      ),
    }));
  },

  setLayerOpacity: (id, opacity) => {
    set((state) => ({
      layers: state.layers.map((l) =>
        l.id === id ? { ...l, opacity } : l
      ),
    }));
  },

  // Comparison actions
  setComparisonMode: (mode) => {
    set((state) => ({
      comparison: { ...state.comparison, mode },
    }));
  },

  setComparisonConfig: (config) => {
    set((state) => ({
      comparison: { ...state.comparison, ...config },
    }));
  },

  addComparisonImage: (imageId) => {
    set((state) => ({
      comparison: {
        ...state.comparison,
        images: [...state.comparison.images, imageId],
      },
    }));
  },

  removeComparisonImage: (imageId) => {
    set((state) => ({
      comparison: {
        ...state.comparison,
        images: state.comparison.images.filter((id) => id !== imageId),
      },
    }));
  },

  // UI actions
  toggleToolbar: () => {
    set((state) => ({ showToolbar: !state.showToolbar }));
  },

  toggleInfo: () => {
    set((state) => ({ showInfo: !state.showInfo }));
  },

  toggleMinimap: () => {
    set((state) => ({ showMinimap: !state.showMinimap }));
  },

  toggleFullscreen: () => {
    set((state) => ({ isFullscreen: !state.isFullscreen }));
  },
}));

